import{_ as o,o as a,c as e,a2 as l}from"./chunks/framework.e-meDy3u.js";const d=JSON.parse('{"title":"附录：代理模式两手准备","description":"","frontmatter":{},"headers":[],"relativePath":"appendix/agent-modes.md","filePath":"appendix/agent-modes.md"}'),r={name:"appendix/agent-modes.md"};function u(p,t,s,i,n,q){return a(),e("div",null,[...t[0]||(t[0]=[l('<h1 id="附录-代理模式两手准备" tabindex="-1">附录：代理模式两手准备 <a class="header-anchor" href="#附录-代理模式两手准备" aria-label="Permalink to &quot;附录：代理模式两手准备&quot;">​</a></h1><p class="hqq-lede">这里有个关键假设我还没法确认：代理是挂昊七七链接分销，还是各自开店自己卖。这个假设影响第三步怎么铺，但不影响地基和第一步。</p><h2 id="先把稳的东西钉住" tabindex="-1">先把稳的东西钉住 <a class="header-anchor" href="#先把稳的东西钉住" aria-label="Permalink to &quot;先把稳的东西钉住&quot;">​</a></h2><p>不管哪种代理模式，有一件事都对：<strong>已经赢过的爆款素材，得有个地方沉淀、打标签、排名，不能散在群聊和某几个人脑子里。</strong></p><p>爆款素材资产库这一层，两种情况都要建。分叉的不是库，是<strong>分发臂的姿态</strong>——是总部往下推（push），还是给代理一个自愿来取的货架（pull）。</p><hr><h2 id="a-手-代理挂链接分销-总部统一供素材-push" tabindex="-1">A 手：代理挂链接分销（总部统一供素材，push） <a class="header-anchor" href="#a-手-代理挂链接分销-总部统一供素材-push" aria-label="Permalink to &quot;A 手：代理挂链接分销（总部统一供素材，push）&quot;">​</a></h2><p>代理用总部素材、回传数据是本分，阻力小。</p><ul><li>分发臂 = 主动推：库里出一个&quot;本周该发什么&quot;视图，代理进来就看到。</li><li>数据回收 = 顺理成章：记一下&quot;发了/没发&quot;，填一个下拉即可。</li><li>增长故事最硬：把赢过的爆款<strong>配方</strong>（不是原样成品，见下面三道坎）铺满代理网，从几个人赢变成全网一起赢。</li></ul><hr><h2 id="b-手-代理各自开店-各自为战-pull" tabindex="-1">B 手：代理各自开店（各自为战，pull） <a class="header-anchor" href="#b-手-代理各自开店-各自为战-pull" aria-label="Permalink to &quot;B 手：代理各自开店（各自为战，pull）&quot;">​</a></h2><p>代理有自己的账号和内容，不能硬发素材，硬发会被当成&quot;总部管太宽&quot;。</p><ul><li>库对代理的身份变成&quot;素材灵感库 / 参考货架&quot;，自愿取用，不是派活。</li><li>代理来取，是因为&quot;好用&quot;（省得自己想选题、降翻车率），不是因为上头要求。</li><li>数据回收改成自愿 + 激励：回传效果的代理能优先拿到下一批爆款配方、进&quot;标杆代理&quot;名单。用红利换数据，不用命令换数据。</li><li>强录入砍掉，换成&quot;取用即埋点&quot;。</li></ul><p>内核没变（还是那个库），变的是它对代理摆出的脸：从管理者变服务者。</p><hr><h2 id="两手都绕不开的三道坎" tabindex="-1">两手都绕不开的三道坎 <a class="header-anchor" href="#两手都绕不开的三道坎" aria-label="Permalink to &quot;两手都绕不开的三道坎&quot;">​</a></h2><p>不管 A 还是 B，只要提&quot;把已赢素材铺给代理&quot;，就会撞上这三件事：</p><p><strong>1. 抖音查重/搬运限流</strong></p><p>同一条视频原样搬到多个代理号发，平台会判重复内容限流；就算付费投，同素材多账号也是自己跟自己竞价内耗 + 素材疲劳。</p><p>解法：库分发给代理的是<strong>爆款配方</strong>（钩子结构、卖点话术、封面公式、脚本模板），要求代理各自重拍/改口播/换脸，不是原样成品。从源头绕开查重。</p><p><strong>2. 达人素材的授权/版权</strong></p><p>速食面抖音爆款很多是达人产出或出镜的。把达人素材沉进库再铺给代理，涉及版权、肖像权、分成——这是法务雷。</p><p>解法：库里的素材<strong>必带&quot;来源/授权状态&quot;字段</strong>（自有拍摄 / 达人授权可分发 / 仅限自营不可分发 / 需重新授权），分发臂对&quot;仅限自营&quot;的素材硬拦截，不许流到代理。</p><p><strong>3. 私店样板对代理的迁移性</strong></p><p>自营号和代理号在账号权重、粉丝画像、客群上都不同，自营跑赢的打法未必在代理号复现。</p><p>解法：话术上别把私店说成&quot;能直接复制到代理的样板&quot;，改成&quot;我先在私店跑通方法论和配方，迁移到代理时按各自实际再调参&quot;。样板证明的是方法论可行，不是素材放哪都赢。</p><hr><h2 id="我押哪一边" tabindex="-1">我押哪一边 <a class="header-anchor" href="#我押哪一边" aria-label="Permalink to &quot;我押哪一边&quot;">​</a></h2><p>给的线索是&quot;很多店铺都在做他们的代理&quot;——更像代理有自己的账号和内容，但巴不得总部给好弹药。纯 A 和纯 B 都是少数，真实生态大多是中间态。</p><p><strong>我的押注：按 B 手的&quot;货架&quot;姿态去搭，但保留 A 手的&quot;主动推&quot;能力。</strong> 库照建，分发默认做成&quot;自愿取用的货架 + 主动推荐给最配合的几个&quot;，数据回收默认走激励。对 A 不亏（愿意听的照样能被推），对 B 也成立（不听的当货架用）。一套东西，两边都不塌。</p><hr><h2 id="入职第一天的验证动作" tabindex="-1">入职第一天的验证动作 <a class="header-anchor" href="#入职第一天的验证动作" aria-label="Permalink to &quot;入职第一天的验证动作&quot;">​</a></h2><p>把&quot;待验证假设&quot;落成具体动作：</p><ol><li>第一天问清：代理是分销链接还是自开店，素材现在谁供，有没有总部统一发素材的先例。</li><li>找 1-2 个最配合的代理直接问：希望总部发成品素材，还是给参考模板自己改？愿不愿意回传数据？</li><li>拿这几个代理先跑样板，验证 push 还是 pull，再决定分发臂的实现。</li></ol><hr><details class="details custom-block"><summary>📱 微信简版 — 如果老板追问代理模式</summary><p>说实话，我方案里有个关键假设我还没法确认：咱们代理是听总部统一发素材，还是各自开店各拍各的。这个决定了分发那一段怎么做，所以我两手都准备了。</p><p>不管哪种，&quot;把已经赢的爆款素材沉淀成一个能打标签、能排名的库&quot;这件事都要做，这是地基，不变。</p><p>分叉在分发：如果代理是分销总部货，那库就配一个&quot;本周该发什么&quot;的视图，主动推给他们，数据也顺理成章能收回来。如果代理是自己开店，那我就把库做成一个&quot;自愿来取的素材货架&quot;，靠好用把他们吸引进来，数据靠激励回传，不硬压。</p><p>我押它大概率在中间——代理有自己的号，但想要总部给好弹药。所以我默认按&quot;给代理一个好用的货架&quot;来做，同时留了主动推的能力，两边都不塌。入职第一天我会去确认到底哪种，再把这一节调实。</p></details>',36)])])}const c=o(r,[["render",u]]);export{d as __pageData,c as default};
